    srcfile, err := os.Open(srcpath)
    if err != nil {
        return err  // os.ErrNotExist if source doesn't exist
    }
    defer srcfile.Close()

    dstfile, err := os.Create(dstpath)
    if err != nil {
        return err
    }
    defer dstfile.Close()

    _, err = io.Copy(dstfile, srcfile)
    return err
}
```

